const body = $input.first().json.body || $input.first().json;
const phone = String(body.phone || '').trim();
const text = String(body.text || '').trim();
const sessionId = body.session_id || null;

if (!phone || !text) {
  return [{ json: { _is_error: true, _error_msg: 'Faltan phone o text', phone, text } }];
}

const staticData = $getWorkflowStaticData('global');
if (!staticData.conversations) staticData.conversations = {};

const now = Date.now();
const MAX_AGE_MS = 24 * 60 * 60 * 1000;
for (const p of Object.keys(staticData.conversations)) {
  const c = staticData.conversations[p];
  if (!c.last_activity || (now - c.last_activity > MAX_AGE_MS)) {
    delete staticData.conversations[p];
  }
}

if (!staticData.conversations[phone]) {
  staticData.conversations[phone] = { history: [], paso_actual: 1, last_activity: now };
}

const conv = staticData.conversations[phone];
conv.last_activity = now;
const historySlice = conv.history.slice(-20);

return [{ json: { phone, text, session_id: sessionId, _conversation_history: historySlice, _paso_actual: conv.paso_actual, _is_error: false } }];

const inputData = $node['Parse Input & Load History'].json;
const catalogRaw = $input.first().json;

// Datos del cliente desde DB
const clienteDb = (() => { try { return $node['MySQL Get Cliente Ventas'].first()?.json || null; } catch(e) { return null; } })();
const vehiculosDb = (() => { try { return $node['MySQL Get Vehiculos Ventas'].all()?.map(i => i.json).filter(v => v && v.id) || []; } catch(e) { return []; } })();
const clienteNombre = (clienteDb?.id && (clienteDb.nombre || clienteDb.apellido)) ? [clienteDb.nombre, clienteDb.apellido].filter(Boolean).join(' ').trim() : null;
const esClienteNuevo = !clienteDb?.id;

const phone = inputData.phone;
const text = inputData.text;
const history = inputData._conversation_history || [];
const paso = inputData._paso_actual || 1;

// Formatear el catálogo de forma estructurada para la IA
let catalogText = '';
try {
  const catalog = typeof catalogRaw === 'string' ? JSON.parse(catalogRaw) : catalogRaw;
  const modelos = catalog.modelos || [];

  if (modelos.length > 0) {
    catalogText += '=== VEHÍCULOS DISPONIBLES ===\n';
    for (const m of modelos) {
      catalogText += `\n### ${m.nombre_completo} (modelo_id: ${m.id})\n`;
      if (m.versiones && m.versiones.length > 0) {
        for (const v of m.versiones) {
          const precioFinal = v.descuento_porcentaje > 0
            ? v.precio_lista * (1 - v.descuento_porcentaje / 100)
            : v.precio_lista;
          const stockStr = v.en_stock
            ? 'EN STOCK'
            : `BAJO PEDIDO (${v.tiempo_entrega_dias} días hábiles)`;
          catalogText += `- ${v.nombre_version} (version_id: ${v.version_id})\n`;
          catalogText += `  Precio: ${v.precio_lista}`;
          if (v.descuento_porcentaje > 0) {
            catalogText += ` | Descuento: ${v.descuento_porcentaje}% | Precio final: ${precioFinal.toFixed(0)}`;
          }
          catalogText += `\n  Disponibilidad: ${stockStr}\n`;
          if (v.colores_disponibles && v.colores_disponibles.length > 0) {
            catalogText += `  Colores: ${Array.isArray(v.colores_disponibles) ? v.colores_disponibles.join(', ') : v.colores_disponibles}\n`;
          }
          if (v.descripcion_equipamiento) {
            catalogText += `  Equipamiento: ${v.descripcion_equipamiento}\n`;
          }
        }
      } else {
        catalogText += '  (Sin versiones disponibles)\n';
      }
      if (m.promociones && m.promociones.length > 0) {
        catalogText += `  PROMOCIONES ACTIVAS:\n`;
        for (const p of m.promociones) {
          catalogText += `  * ${p.descripcion}${p.valor ? ' — ' + p.valor : ''}${p.fecha_fin ? ' (hasta ' + p.fecha_fin + ')' : ''}\n`;
        }
      }
    }
  } else {
    catalogText += 'No hay vehículos disponibles en el catálogo.\n';
  }

  if (catalog.promociones_globales && catalog.promociones_globales.length > 0) {
    catalogText += '\n=== PROMOCIONES GENERALES ===\n';
    for (const p of catalog.promociones_globales) {
      catalogText += `- ${p.descripcion}${p.valor ? ' — ' + p.valor : ''}\n`;
    }
  }

  if (catalog.financiamiento) {
    const fin = typeof catalog.financiamiento === 'string' ? catalog.financiamiento : JSON.stringify(catalog.financiamiento, null, 2);
    catalogText += `\n=== OPCIONES DE FINANCIAMIENTO (usar en Paso 5) ===\n${fin}\n`;
  }

  if (catalog.documentacion_natural || catalog.documentacion_juridico) {
    catalogText += '\n=== DOCUMENTACIÓN REQUERIDA (usar en Paso 6) ===\n';
    if (catalog.documentacion_natural) {
      const d = typeof catalog.documentacion_natural === 'string' ? catalog.documentacion_natural : JSON.stringify(catalog.documentacion_natural, null, 2);
      catalogText += `Persona natural:\n${d}\n`;
    }
    if (catalog.documentacion_juridico) {
      const d = typeof catalog.documentacion_juridico === 'string' ? catalog.documentacion_juridico : JSON.stringify(catalog.documentacion_juridico, null, 2);
      catalogText += `Persona jurídica:\n${d}\n`;
    }
  }

  if (catalog.garantias || catalog.servicios_adicionales) {
    catalogText += '\n=== GARANTÍAS Y SERVICIOS ADICIONALES (mencionar en Paso 7) ===\n';
    if (catalog.garantias) {
      const g = typeof catalog.garantias === 'string' ? catalog.garantias : JSON.stringify(catalog.garantias, null, 2);
      catalogText += `Garantías: ${g}\n`;
    }
    if (catalog.servicios_adicionales) {
      const s = typeof catalog.servicios_adicionales === 'string' ? catalog.servicios_adicionales : JSON.stringify(catalog.servicios_adicionales, null, 2);
      catalogText += `Servicios adicionales: ${s}\n`;
    }
  }

} catch (e) {
  catalogText = 'ERROR: No se pudo cargar el catálogo.';
}

// Contexto del cliente
let clienteContext = '';
if (!esClienteNuevo) {
  const vehiculosStr = vehiculosDb.length > 0
    ? vehiculosDb.map(v => `${v.brand} ${v.model} ${v.year}${v.plate ? ' (' + v.plate + ')' : ''}${v.current_mileage > 0 ? ' | ' + v.current_mileage + ' km' : ''}`).join(', ')
    : 'ninguno registrado';
  clienteContext = `=== CLIENTE REGISTRADO ===\nNombre: ${clienteNombre}\nTeléfono: ${phone}\nVehículos actuales: ${vehiculosStr}\n`;
} else {
  clienteContext = `=== CLIENTE NUEVO (primera vez) ===\nTeléfono: ${phone}\n`;
}

const systemMsg = `Eres un asesor de ventas de IA para una empresa automotriz. Atiendes clientes por WhatsApp con calidez y profesionalismo.

${clienteContext}
${catalogText}

=== RESPUESTA: SIEMPRE JSON ESTRICTO (sin texto fuera del bloque JSON) ===
{
  "action": "continue" | "save_lead" | "escalate" | "redirect_taller",
  "paso_actual": <1-7>,
  "message": "<mensaje para WhatsApp>",
  "lead_data": { <solo incluir cuando action es save_lead o redirect_taller> }
}

=== MENÚ PRINCIPAL ===
SIEMPRE muestra este menú cuando la conversación empiece o el cliente no haya seleccionado una opción claramente:

🚗 *1 – Comprar un auto nuevo*
🔧 *2 – Consultar precio de mantenimiento*
💬 *3 – Hablar con un asesor*

Escribe el número o el ícono de lo que necesitas.

=== REGLAS DE ENRUTAMIENTO ===
Si el cliente elige 🔧 (2 / "mantenimiento" / "servicio" / "taller" / "afinamiento" / "aceite" / "revisión"):
  → action: "redirect_taller"
  → message: mensaje amigable indicando que lo transferirás al área de mantenimiento
  → lead_data: { "nombre_cliente": "${clienteNombre || ''}", "canal": "whatsapp" }

Si el cliente elige 💬 (3 / "asesor" / "hablar con alguien" / "persona real" / "humano"):
  → action: "escalate"

Si el cliente elige 🚗 (1 / "comprar" / "auto nuevo" / "cotización" / "quiero un auto"):
  → Continúa con el FLUJO DE COMPRA de 7 pasos
  ${esClienteNuevo ? '→ El cliente es NUEVO: en el paso 1 saluda y pide su nombre. Pregunta si ya tiene un vehículo.' : `→ El cliente ya está registrado como ${clienteNombre}. Salúdalo por su nombre directamente. ${vehiculosDb.length > 0 ? 'Ya tiene vehículo(s) registrado(s): no preguntes si tiene uno, úsalo como referencia si aplica.' : 'No tiene vehículos registrados.'}`}

=== FLUJO DE COMPRA ===
Estado actual: Paso ${paso} de 7

PASO 1 – BIENVENIDA: ${esClienteNuevo ? 'Saluda y pide el nombre del cliente. Pregunta si ya tiene un vehículo actualmente.' : `Saluda a ${clienteNombre} por su nombre. Confirma interés en comprar.`}
PASO 2 – NECESIDADES: ¿Para qué usará el vehículo? ¿Cuántas personas lo usarán habitualmente?
PASO 3 – PREFERENCIAS: Presenta 2-3 categorías según el uso. Pregunta tipo, combustible, colores y equipamiento deseado.
PASO 4 – OPCIONES CONCRETAS: Presenta 1-2 vehículos del catálogo con precio, disponibilidad (EN STOCK o BAJO PEDIDO + días), colores y equipamiento. Menciona promociones activas.
PASO 5 – PRESUPUESTO Y PAGO: ¿Contado o financiamiento? Si financia: presenta opciones de plazo y cuota inicial con las tasas del catálogo.
PASO 6 – PLAZOS Y DOCUMENTACIÓN: Confirma tiempo de entrega. Menciona documentación requerida (natural o jurídico según corresponda).
PASO 7 – RESUMEN Y CIERRE: Presenta resumen completo. Cuando el cliente confirme → action: "save_lead".

=== DATOS PARA SAVE_LEAD ===
{
  "nombre_cliente": "${clienteNombre || '...'}",
  "email": "${clienteDb?.email || '...'}",
  "modelo_id": <ID exacto del catálogo>,
  "version_id": <ID exacto del catálogo>,
  "modelo_nombre": "...",
  "version_nombre": "...",
  "precio_final": <número>,
  "moneda": "PEN",
  "forma_pago": "contado" | "financiamiento",
  "plazo_meses": <número o null>,
  "cuota_inicial": <número o null>,
  "tiempo_entrega_dias": <número>,
  "uso_vehiculo": "...",
  "personas_habituales": <número>,
  "presupuesto_rango": "...",
  "equipamiento_requerido": "...",
  "tiene_historial_crediticio": true | false | null,
  "notas_agente": "..."
}

=== REGLAS GENERALES ===
- Responde en español, amigable y conciso (máx. 280 palabras por mensaje)
- NUNCA inventes precios, modelos ni versiones fuera del catálogo
- precio_final = precio_lista × (1 − descuento_porcentaje/100)
- Si el cliente pregunta algo fuera del scope → action: "escalate"
- Recuerda el menú si la conversación lleva 2+ turnos sin dirección clara`;

const messages = [
  { role: 'system', content: systemMsg },
  ...history,
  { role: 'user', content: text }
];

return [{ json: { phone, text, session_id: inputData.session_id, _paso_actual: paso, _messages: messages } }];

const httpResp = $input.first().json;
const inputData = $node['Build AI Prompt'].json;

const httpStatus = Number(httpResp.statusCode || httpResp.status || 200);
const respBody = httpResp.body || httpResp;

let rawText = '';
try {
  const body = typeof respBody === 'string' ? JSON.parse(respBody) : respBody;
  rawText = body?.choices?.[0]?.message?.content?.trim() || '';
} catch(e) {
  rawText = '';
}

let parsed = { action: 'continue', paso_actual: inputData._paso_actual || 1, message: '', lead_data: {} };
try {
  const jsonMatch = rawText.match(/```json\s*([\s\S]*?)\s*```/) ||
                    rawText.match(/```\s*([\s\S]*?)\s*```/) ||
                    rawText.match(/({[\s\S]*})/);
  const jsonStr = jsonMatch ? (jsonMatch[1] || jsonMatch[0]) : rawText;
  parsed = JSON.parse(jsonStr.trim());
} catch (e) {
  parsed.message = rawText || 'Lo siento, tuve un problema. Por favor escribe nuevamente o escribe "agente" para hablar con una persona.';
  parsed.action = 'continue';
}

const VALID_ACTIONS = ['continue', 'save_lead', 'escalate', 'redirect_taller'];
if (!VALID_ACTIONS.includes(parsed.action)) parsed.action = 'continue';
if (!parsed.message) parsed.message = 'Un momento, estoy procesando tu solicitud.';

const staticData = $getWorkflowStaticData('global');
if (!staticData.conversations) staticData.conversations = {};

const phone = inputData.phone;
if (!staticData.conversations[phone]) {
  staticData.conversations[phone] = { history: [], paso_actual: 1, last_activity: Date.now() };
}

const conv = staticData.conversations[phone];
conv.history.push({ role: 'user', content: inputData.text });
conv.history.push({ role: 'assistant', content: parsed.message });
if (conv.history.length > 40) conv.history = conv.history.slice(-40);
conv.paso_actual = parsed.paso_actual || conv.paso_actual;
conv.last_activity = Date.now();

if (parsed.action === 'save_lead' || parsed.action === 'escalate' || parsed.action === 'redirect_taller') {
  delete staticData.conversations[phone];
}

return [{ json: { phone: inputData.phone, session_id: inputData.session_id, text: inputData.text, _action: parsed.action, _paso_actual: parsed.paso_actual || inputData._paso_actual, _reply_msg: parsed.message, _lead_data: parsed.lead_data || {}, _llm_ok: httpStatus >= 200 && httpStatus < 300 } }];
